// Extract the lead email from the Instantly webhook payload.
// Instantly webhook structure varies by plan — adjust field paths if needed.

const body = $input.first().json.body || $input.first().json;

// Instantly sends lead data under different keys depending on event type.
// Common fields: lead_email, email, contact_email
const leadEmail = (
  body.lead_email ||
  body.email ||
  body.contact?.email ||
  body.lead?.email ||
  ''
).toLowerCase().trim();

const eventType   = body.event_type || body.type || 'reply';
const campaignId  = body.campaign_id || body.campaign?.id || '';
const replySnippet = body.reply_text || body.text || body.snippet || '';

if (!leadEmail) {
  throw new Error('Instantly webhook payload did not contain a recognizable email field. Check payload structure and update this node.');
}

return [{
  json: {
    lead_email:     leadEmail,
    event_type:     eventType,
    campaign_id:    campaignId,
    reply_snippet:  replySnippet,
    received_at:    new Date().toISOString()
  }
}];
